import random

def gradient_ascent(f, x_init, learning_rate, num_iterations, eps=1e-6):
    x = x_init
    for i in range(num_iterations):
        grad = [f(x + eps * e_i) - f(x) for e_i in [(1, 0), (0, 1)]]
        x = [x_i + learning_rate * g_i for x_i, g_i in zip(x, grad)]
        if sum(abs(g) for g in grad) < eps:
            break
    return x

