import math

def gradient_ascent(f, x0, epsilon=1e-5, max_iterations=1000):
    x = x0
    prev_x = x - 2 * epsilon
    iterations = 0

    while abs(x - prev_x) > epsilon and iterations < max_iterations:
        prev_x = x
        gradient = [
            (f([x[i] + epsilon] + x[:i] + x[i+1:]) - f(x)) / epsilon
            for i in range(len(x))
        ]
        x = [x_i + step_size * grad_i for x_i, grad_i in zip(x, gradient)]
        iterations += 1

    return x

def sphere_function(x):
    return sum(x_i ** 2 for x_i in x)

x0 = [2, 3, 4]
result = gradient_ascent(sphere_function, x0)
